arguments.new_str:
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
builder.Services.AddSingleton(new TicketClassifierService(dataPath));

var app = builder.Build();

app.MapPost("/api/ticket/classify", (TicketRequest request, TicketClassifierService classifier) =>
{
    if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
        return Results.BadRequest("Subject or Description is required.");

    if (request.Priority < 1 || request.Priority > 3)
        return Results.BadRequest("Priority must be between 1 and 3.");

    return Results.Ok(classifier.Predict(request));
});

app.MapGet("/api/ticket/metrics", (TicketClassifierService classifier) =>
{
    return Results.Ok(classifier.Evaluate());
});

app.Run();

